        long nanos = System.nanoTime();
        //ナノ→マイクロへの変換
        long micro = TimeUnit.NANOSECONDS.toMicros(nanos);
        //ナノ→秒への変換(マイクロと比較するために10^6をかける)
        long seconds = TimeUnit.NANOSECONDS.toSeconds(nanos)*1000000;
        //マイクロ秒－秒をとりマイクロ秒だけを切り出す。
        long mirco2 = micro-seconds;
        //現在時刻をyyyyMMddhhmmssでとる
        SimpleDateFormat sdf = new SimpleDateFormat("yyyyMMddhhmmss");
        //yyyyMMddhhmmssとマイクロ秒を結合
        String dateFormatMicro = sdf.format(c.getTime()) + mirco2;

　　　　System.out.print(dateFormatMicro);
}</pre>

