<h3>複雑なメソッドの実装</h3>
さらに進歩させました。

自分がやりたかったのはSQL構築のメソッドであり、
以下が簡単な使用です。
<ul>
 	<li>フィールド名と値を代入したい</li>
 	<li>メソッドは前もって実装済み</li>
 	<li>通常時は演算子を引数にとり、代入</li>
 	<li>LikeのときのみＳＱＬ文自体をオーバーライドしたい</li>
 	<li>文字と数字でクオートの有無を変えたい</li>
</ul>
<pre class="lang:java decode:true "> public static void main(String[] args) {

        Operator op1 = LIKE;
        Operator op2 = EQUAL;

        System.out.println(op1.getQuery("namae", "atai")); // namae like binary '%atai%'
        System.out.println(op2.getQuery("namae", "atai")); // namae = 'atai'
        System.out.println(op2.getQuery("namae", 10)); // namae == 10

    }

    enum Operator {

        LIKE {
                @Override
                public String getQuery(String name, String value) {
                    String query= name + " like binary '%" + value + "%'"
					return query;
                }
            },
        LIKE_L {
                    @Override
                    public String getQuery(String name, String value) {
                        String query = name + "like binary '" + value + "%'";
                        return query;
                    }
                },
				
        NOT_EQUAL( " != "),	
        EQUAL(" = ");

        private String mark;

        Operator(String mark) {
            this.mark = mark;
        }

        Operator() {
            this.mark = null;
        }

        public String getQuery(String name, String value) {
            String query = name + " " + this.mark + " '" + value + "'";
            return query;
        }

        public String getQuery(String name, int value) {
            String query = name + " " + this.mark + " " + value;
            return query;
        }

    }

</pre>

