Windows8
Java7
Glassfish 4.1

です。

なお、一部のプログラムが<a href="http://skill-up-engineering.com/?p=397" target="_blank" rel="noopener">前回の記事</a>と同じです。
<pre class="lang:java decode:true">package com.person.beans;

import com.person.ejb.PersonFacade;
import com.person.entity.Person;
import java.io.IOException;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.logging.Level;
import java.util.logging.Logger;
import javax.ejb.EJB;
import javax.ejb.Stateless;
import javax.ws.rs.GET;
import javax.ws.rs.Path;
import org.codehaus.jackson.map.ObjectMapper;


@Path("ping")//ここはURLの一部になります。
@Stateless//glassgishを使う場合書かないとエラーになります。
public class JavaAPI {

    @EJB //@Injectだとエラーがでます。
    PersonFacade personFacade;


    /**
     * @return
     */
    @GET //GETでアクセスする場合このアノテーションが必要です。
    public String getAllToJson() {

        String json = null;
        try {
            List&lt;Person&gt; personList = personFacade.findAll();
            ObjectMapper objectMapper = new ObjectMapper();
            Map&lt;String, List&lt;Person&gt;&gt; personMap = new HashMap&lt;&gt;();
            personMap.put("aaData", personList);
            json = objectMapper.writeValueAsString(personMap);
        } catch (IOException ex) {
            Logger.getLogger(PersonBean.class.getName()).log(Level.SEVERE, null, ex);
        }
        return json;
    }

}
</pre>
