        DateUtility du = new DateUtility();
        Date nowDate = du.stringToDate(targetDate);
        ConstantExpense ce = menuFacade.getConstantExpense(userBean.getUserId(), nowDate);

        if (ce != null) {
            this.fixedSalary = ce.getFixedSalary().toString();
            this.transportationSalary = ce.getTransportationSalary().toString();
        }
    }</pre>
