<pre class="lang:php decode:true">	/**
	 * スタッフユーザー追加
	 */
	public function useradd() {

		// POST の時だけ
		if ($this-&gt;request-&gt;is ( 'post' )) {
			if ($this-&gt;User-&gt;save ( $this-&gt;request-&gt;data )) {
				$this-&gt;Session-&gt;setFlash ( __ ( 'スタッフの登録が成功しました。' ) );
				$this-&gt;redirect ( array (
						'action' =&gt; 'index'
				) );
			} else {
				$this-&gt;Session-&gt;setFlash ( 'スタッフの登録に失敗しました。' );
			}
		}
		$this-&gt;render ( 'userregist' );
	}


	/**
	 * スタッフユーザーの情報を更新
	 *
	 * @param unknown $id
	 * @throws NotFoundException
	 */
	public function userupdate($id = null) {
		$this-&gt;User-&gt;id = $id;

		if (! $this-&gt;User-&gt;exists ()) {
			throw new NotFoundException ( __ ( 'データが存在しません。' ) );
		}

		if ($this-&gt;request-&gt;is ( 'post' ) || $this-&gt;request-&gt;is ( 'put' )) {
			if ($this-&gt;User-&gt;save ( $this-&gt;request-&gt;data )) {
				$this-&gt;Session-&gt;setFlash ( __ ( 'スタッフの編集が成功しました。' ) );
				$this-&gt;redirect ( array (
						'action' =&gt; 'index'
				) );
			} else {
				$this-&gt;Session-&gt;setFlash ( __ ( 'スタッフの情報を編集することができませんでした。もう一度実行してください。' ) );
			}
		} else {
			$this-&gt;request-&gt;data = $this-&gt;User-&gt;read ( null, $id );
		}
		$this-&gt;render ( 'userregist' );
	}</pre>
