普段はJavaEEで開発を行っているのでデータベースへのアクセスはJPAを活用しています。

ただ、JavaEE環境だとglassfish経由でデータベースを動かしているので、glassfishを動かさずにデータベースへのアクセスをしたいときに、通常はアクセスできません。

そこで緊急的に直でデータベースにアクセスできる手法を探しました。

個人的な要望としては下記のような状態です。
<ul>
 	<li>JDBCは知っているのですが、もっとスマートにかけるほうほうをしりたい</li>
 	<li>デバッグなども簡単にできる</li>
 	<li>通常のSQLであってもO/Rマッパーでもどちらでもよい。</li>
 	<li>なるべく設定ファイルなどを追加しないほうがいい</li>
 	<li>JPAでGlassfish経由でなく直にアクセスする方法はしっているが設定がめんどい＆少し遅い</li>
</ul>
こんな方法をいろいろと考えていましたが、DBUtilsというライブラリが便利で、上記条件を満たしているので使うことに。

※似た名前でDBUnitsというものがありますがこれは違います。
<h3>インストール</h3>
例によって下記をpomに追加します。

<a href="http://mvnrepository.com/artifact/commons-dbutils/commons-dbutils/1.5" target="_blank" rel="noopener">http://mvnrepository.com/artifact/commons-dbutils/commons-dbutils/1.5</a>
<pre class="lang:java decode:true">    &lt;dependency&gt;	
        &lt;groupId&gt;commons-dbutils&lt;/groupId&gt;	
        &lt;artifactId&gt;commons-dbutils&lt;/artifactId&gt;	
        &lt;version&gt;1.6&lt;/version&gt;
    &lt;/dependency&gt;</pre>
<h3>コード</h3>
<ul>
 	<li>selectでは型を指定し、SQLを入力すればOK</li>
 	<li>よくMap、List&lt;Map&gt;のデータをinsertしたいケースがあるので、これ用のメソッドを容易</li>
 	<li>updateというメソッドはSQLのinseert,update,delete全てを含みます。単純にSQLを投げればOK</li>
</ul>
バインドさせているものと、いないものがあったりとあまり統一性はないので(とりあえずテストデータのinsertと抽出ができればOKだったので)詳しく仕様を見たい方はリンク先を見てみてください。
<pre class="lang:java decode:true ">public class DBUtilsConnect{
　　　/**
     * 接続情報
     */
    @Setter
    @Getter
    private Connection con = null;

    /**
     * URL
     */
    @Getter
    @Setter
    private String url = "";

    /**
     * ユーザー
     */
    @Getter
    @Setter
    private String user = "";

    /**
     * パスワード
     */
    @Getter
    @Setter
    private String password = "";

    /**
     * クエリランナー
     */
    @Getter
    @Setter
    private QueryRunner qr = null;

    /**
     * コンストラクタで初期データのセット
     */
    public DBUtilsConnect() {
        this.url = "jdbc:mysql://DBのホスト/データベース名";
        this.user = "ユーザー名";
        this.password = "パスワード";
    }

    /**
     * DBに接続
     */
    public void connect() {
        try {
            Class.forName("org.gjt.mm.mysql.Driver");
            Connection tmpCon = null;
            try {
                tmpCon = DriverManager.getConnection(url, user, password);
                con = tmpCon;
                qr = new QueryRunner();
            } catch (SQLException ex) {
                Logger.getLogger(DBUtilsConnect.class.getName()).log(Level.SEVERE, null, ex);
            } 
        } catch (ClassNotFoundException ex) {
            Logger.getLogger(DBUtilsConnect.class.getName()).log(Level.SEVERE, null, ex);
        }
    }

    /**
     * DBとの接続を閉じる
     */
    public void close() {
        try {
            this.con.close();
        } catch (SQLException ex) {
            Logger.getLogger(DBUtilsConnect.class.getName()).log(Level.SEVERE, null, ex);
        }
    }

    /**
     * 特定のSQLを読み込んでエンティティを返す
     *
     * @param &lt;T&gt; 型
     * @param clazz 型情報
     * @param selectQuery クエリ
     * @return　LIst型パラメータ
     */
    public &lt;T&gt; List&lt;T&gt; select(Class&lt;T&gt; clazz, String selectQuery) {

        List&lt;T&gt; entityList = new ArrayList&lt;&gt;();
        try {
            this.connect();
            ResultSetHandler rsh = new BeanListHandler(clazz);
            entityList = (List) qr.query(con, selectQuery, rsh);
            this.close();
        } catch (SQLException ex) {
            Logger.getLogger(DBUtilsConnect.class.getName()).log(Level.SEVERE, null, ex);
        }
        return entityList;
    }

    /**
     * LIST/MAP系のデータを一括でインサートする
     * 
     * @param tableName　テーブル名
     * @param dataList LIST/MAPのデータ
     */
    public void ListMapToInsert(String tableName, List&lt;Map&lt;String, String&gt;&gt; dataList) {
        dataList.stream().forEach(map -&gt; {
            MapToInsert(tableName, map);   
        });
    }
    
    /**
     * MAP型式のデータをインサートする
     *
     * @param tableName テーブル名
     * @param map インサートするMap
     */
    public void MapToInsert(String tableName, Map&lt;String, String&gt; map) {
      
        Set&lt;String&gt; keySet = map.keySet();
        Object[] valueSet = map.values().toArray();
        
        String bind = StringUtils.repeat("?", ",", valueSet.length);
        String keyCol = StringUtils.join(keySet, ",");
        String insQuery = String.format(" INSERT INTO  %s ( %s )  VALUES ( %s ) ", tableName, keyCol, bind);
       
        this.connect();
        try {
            qr.update(con, insQuery, valueSet);
        } catch (SQLException ex) {
            Logger.getLogger(DBUtilsConnect.class.getName()).log(Level.SEVERE, null, ex);
        }
        this.close();
    }
    
    /**
     * 新規作成(INSERT)、更新(UPDATE)、削除(DELETE)のメソッド
     *
     * @param updateQuery 更新のクエリ
     */
    public void update(String updateQuery) {
        try {
            this.connect();
            qr.update(con, updateQuery);
            this.close();
        } catch (SQLException ex) {
            Logger.getLogger(DBUtilsConnect.class.getName()).log(Level.SEVERE, null, ex);
        }
    }
}
</pre>
