<h3>ソース</h3>
ちなみにエクセルやxmlのパスはsrc/main/resources直下です。
<pre class="lang:java decode:true">public class DBUtiliTest {

    /**
     * DBのコネクション
     */
    private Connection dbConnet = null;

    /**
     * IDatabaseコネクション
     */
    private IDatabaseConnection idbConnect = null;

    /**
     * host
     */
    private String dbhost;

    /**
     * port
     */
    private String port;

    /**
     * DB名
     */
    private String dbName;

    /**
     * DBユーザー
     */
    private String dbUser;

    /**
     * DBパス
     */
    private String dbPass;

    /**
     * DBユーティリティー
     */
    private DBUtility dbUtility = null;

    /**
     * ファイルパス
     */
    private String fileDirPath;

    /**
     * バックアップファイル名
     */
    private String backUpFileName;

    /**
     * 事前入力ファイル
     */
    private String preInsFileName;

    /**
     * 期待値ファイル名
     */
    private String expectFileName;

	@Test
    public void testStart() {
　　　　　//設定情報の入力
        this.initConfData();
        //データベースとつなぎます
        this.connectDbConnect();
        //DBunitのデータベースオブジェクトとつなぎます。
        this.connecIdbConnect();
        //バックアップを取得します。
        this.backUP();
        //事前データを入力します。
        this.preSetData();
        //実際にデータを更新する処理です。
        //この処理はこのプログラムの中に書かれてはないです。
        this.updateTemplate();
        //期待値と対象のデータが等しいかどうかのチェックを行います。
        this.chechExpectedData();
        //最後にテストで行ったデータを削除し、バックアップxmlをリストアします。
        this.tearDown();
    }

    /**
     * 基本データを設定する
     */
    public void initConfData() {
        this.dbhost = "ホスト情報";
        this.dbName = "データベース名";
        this.dbUser = "ユーザー";
        this.dbPass = "パスワード";
        this.backUpFileName = "バックアップとして保存したいxmlファイルの名前";
        this.preInsFileName = "事前データとしていれたいエクセルファイルの名前";
        this.expectFileName = "期待値となるエクセルファイルの名前";        
        this.setFileDir();
    }

    /**
     * DBとの接続
     */
    private void connectDbConnect() {
        try {
            Class.forName("com.mysql.jdbc.Driver");
            this.dbConnet = DriverManager.getConnection(this.getDbUrl(), this.dbUser, this.dbPass);
        } catch (SQLException ex |  ClassNotFoundException ex) {
            Logger.getLogger(DBUtiliTest.class.getName()).log(Level.SEVERE, null, ex);

        }
    }
    /**
     * IDBとの接続
     */
    private void connecIdbConnect() {
        try {
            this.idbConnect = new DatabaseConnection(this.dbConnet);
        } catch (DatabaseUnitException ex) {
            Logger.getLogger(DBUtiliTest.class.getName()).log(Level.SEVERE, null, ex);
        }
    }

    /**
     * URLの発行
     *
     * @return DBURL
     */
    private String getDbUrl() {
        return String.format("jdbc:mysql://%s:%s/%s?useUnicode=true&amp;characterEncoding=utf8", this.dbhost, this.port, this.dbName);
    }

    /**
     * 事前データのセット
     */
    public void preSetData() {
        try {
            //データセットの取得
            IDataSet dataSet = new XlsDataSet(new FileInputStream(this.getPreDataPath()));
            //セットアップ実行
            DatabaseOperation.CLEAN_INSERT.execute(this.idbConnect, dataSet);

        } catch (IOException | DatabaseUnitException | SQLException ex) {
            Logger.getLogger(DBUtiliTest.class.getName()).log(Level.SEVERE, null, ex);
        }
    }

    public void chechExpectedData(){
        try {
            IDataSet dataSet = new XlsDataSet(new FileInputStream(this.getExcepctedDataPath()));
            String sql =" select * from template where id = 1 ";
            //作成日、更新日など照合の対象とならないデータです。
            String[] ignoreCols={"create_dt","update_dt"};
　　　　　　　//ここで対象となるデータとエクセルが等しいかをチェックできます。
            Assertion.assertEqualsByQuery(dataSet,this.idbConnect,sql,"template", ignoreCols);
        } catch (IOException | DatabaseUnitException | SQLException ex) {
            Logger.getLogger(DBUtiliTest.class.getName()).log(Level.SEVERE, null, ex);
        }

    }

    /**
     * ディレクトリの設定
     */
    private void setFileDir() {
        this.fileDirPath = System.getProperty("user.dir") + File.separator + "src" + File.separator + "main" + File.separator + "resources" + File.separator;
    }

    /**
     * バックアップファイルパス
     *
     * @return バックアップデータのファイルパス
     */
    private String getBackUpDataPath() {
        return this.fileDirPath + this.backUpFileName;
    }

    /**
     * 事前データのファイルパス
     *
     * @return 事前データファイルパス
     *
     */
    private String getPreDataPath() {
        return this.fileDirPath + this.preInsFileName;
    }

    /**
     * 期待値データのファイルパス
     *
     * @return 期待値ファイルパス
     */
    private String getExcepctedDataPath() {
        return this.fileDirPath + this.expectFileName;
    }

    /**
     * データのバックアップ
     */
    public void backUP() {
        try {
            // バックアップを取りたいテーブルを列挙
            IDataSet dataSet = this.idbConnect.createDataSet();
            XmlDataSet.write(dataSet, new FileOutputStream(this.getBackUpDataPath()));
        } catch (IOException | SQLException | DataSetException ex) {
            Logger.getLogger(DBUtiliTest.class.getName()).log(Level.SEVERE, null, ex);
        }
    }

    /**
     * データのリストア
     */
    public void tearDown() {
        // setUp()で生成したバックアップファイルを引数に再度データをinsert
        try {
            IDataSet dataSet = new XmlDataSet(new FileInputStream(this.getBackUpDataPath()));
            DatabaseOperation.CLEAN_INSERT.execute(this.idbConnect, dataSet);
        } catch (FileNotFoundException | DatabaseUnitException | SQLException ex) {
            Logger.getLogger(DBUtiliTest.class.getName()).log(Level.SEVERE, null, ex);
        }

    }

    public void updateTemplate(){
        this.dbUtility = new DBUtility();
        this.dbUtility.setUrl(this.getDbUrl());
        this.dbUtility.setUser(this.dbUser);
        this.dbUtility.setPassword(this.dbPass);
        Template template = this.dbUtility.findById(1);
        template.setDescription("sample2");
        this.dbUtility.regist(template);                
    }

}
</pre>
説明はほぼコード上のコメントに集約されているかと思います。
<h3>注意点</h3>
<ul>
	<li> もとからあるデータをバックアップしてからリストアするまでに処理が失敗するとリストアされません。
例外時にリストアのメソッドをいれておかないと面倒です。</li>
	<li>事前データとして入力する日付の値はyyyy/MM/ddにしておきましょう。</li>
	<li>期待値のエクセルでは日付をyyyy-MM-ddにしておき、文字列にしておかないとダメです。日付だと自動でyyyy/MM/ddになってしまいます。</li>
</ul>
