					'foreignKey'             =&gt; 'item_id',
					'associationForeignKey'  =&gt; 'tag_id',
					'unique'                 =&gt; true
				]
			];
}</pre>
Tag.php
<pre class="lang:php decode:true ">class Tag extends Model {

	public $hasAndBelongsToMany = [
			'Item' =&gt;
			[
					'className'              =&gt; 'item',
