<pre class="lang:php decode:true ">//こちらでinclude_pathを設定します。
set_include_path( __DIR__ . '/vendor/');

require_once 'setasign/fpdf/fpdf.php';
require_once 'setasign/fpdi/japanese.php';

$pdf = new PDF_Japanese();
//ページ追加
$pdf-&gt;AddPage();

$pdf-&gt;setSourceFile('テンプレートのファイルパス');
$tplIdx = $pdf-&gt;importPage(1);
$pdf-&gt;useTemplate($tplIdx, 0, 0, 210, 296 );

$pdf-&gt;AddSJISFont();
$pdf-&gt;SetFont('SJIS');

setMessage( $pdf, 149, 41.3 , "29");
setMessage( $pdf, 164, 41.3 , "2");
setMessage( $pdf, 177, 41.3 , "4");
setMessage( $pdf, 40, 48 , "サンプル商事");


setMessage( $pdf, 48, 101.8 , "2");
setMessage( $pdf, 55.6, 101.8 , " 1");

setMessage( $pdf, 67, 101.8 , "2");
setMessage( $pdf, 74, 101.8 , "28");

$pdf-&gt;Output();

function setMessage( &amp;$pdf ,$x, $y, $str ) {
 $pdf-&gt;SetTextColor(0, 0, 0);
 $pdf-&gt;SetXY($x, $y);
 $pdf-&gt;Write(0, mb_convert_encoding($str,'SJIS','UTF-8'));
}

