こちらも下記のようにしてモジュール登録し、呼び出したい側で読み込めばOKです。ファイル名をconstant.jsとします。

constant.js
<pre class="lang:js decode:true">var appConf = angular.module('appConf', []).constant('CONFIG', {
      DOMAIN:'http://192.168.33.10',
      URL_BASE: 'http://192.168.33.10/hogehoge/'
});
~</pre>
呼び出したい側
<pre class="lang:js decode:true">var app = angular.module("app", ['appUtil','appConf'])
app.controller("mainCtrl", ['$scope', '$http', '$location' , '$filter' , 'utils' , 'CONFIG',function ( $scope, $http , $location, $filte ,utils ,CONFIG) {  
    console.log(CONFIG.DOMAIN)
});</pre>
