<pre class="lang:css decode:true">.image_block{
	display: inline-block;
	width: 320px;
	height: 400px;
	margin-right: 15px;
	overflow: hidden;
	background: #eee;
	position: relative;
}

.image_block:nth-child(3n){
	margin-right: 0;
}

.img_elem{
	position: absolute;
	top:50%;
	left:50%;
	max-height: 100%;
	height: auto;
	width: auto;
