step3 地図をカスタマイズして貼り付ける。
<pre class="lang:js decode:true ">  var geocoder = new google.maps.Geocoder();
  geocoder.geocode({
    'address': '東京都中央区1-1-1',
    'region': 'jp'
  },function (results, status) {
　  if (status == 'OK') {
      var map_location = new google.maps.LatLng(results[0].geometry.location.lat(),results[0].geometry.location.lng());
      var map_option = {
          zoom: 16,
          center: map_location,
          mapTypeId: google.maps.MapTypeId.ROADMAP,
          styles: [{stylers: [{hue: '#00a85f' }]}]
          };
      //ここに実際の地図のDOM要素が入ります。
      var map = new google.maps.Map(document.getElementById('google_map_block'), map_option);
      //ここをつけてあげると地図上に目印がたちます。
      var marker0 = new google.maps.Marker({position: map_location,map: map});
    }
  });</pre>
