S3のcommandPoolに関して。

S3にファイルをアップロード、ダウンロードするときに、1つ1つファイルをアップロード、ダウンロードすることが一般的かと思いますが、ファイル数が多くなるとなかなか時間がかかってしまいます。

そこで一気にファイルをアップロード、ダウンロードできる手法があります。

要領としてはコマンドをあらかじめ登録しておき、一気に処理を行うというもので、SQLのバルクインサート(bulk insert)などに近いと思います。

ソース

CommandPool.php
<pre class="lang:default decode:true ">&lt;?php
require_once __DIR__ . '/vendor/autoload.php';
require_once __DIR__ . '/AWSS3Util.php';
$dotenv = Dotenv\Dotenv::create(__DIR__);
$dotenv-&gt;load();
$aws3Util = new AWSS3Util([
    'aws_access_key' =&gt; getenv('ACCESS_KEY'),
    'aws_secret_key' =&gt; getenv('SECRET_KEY'),
    'region' =&gt; getenv('REGION')
]);
bulkUpload($aws3Util);
bulkDownload($aws3Util);
function bulkDownload($aws3Util)
{
    $saveFileDir = __DIR__ . '/sample_image';
    $fileLists = $aws3Util-&gt;getS3FileList(getenv('BUCKET_NAME'), 'sample_image');
    $imageData = [];
    foreach ($fileLists as $file) {
        if (!empty($file)) {
             $imageData[] = 'sample_image/' . $file;
        }
    }
    $aws3Util-&gt;bulkSaveS3Contents(getenv('BUCKET_NAME'), $saveFileDir, $imageData);
}
function bulkUpload($aws3Util)
{
    $dir = __DIR__ . '/sample_image/*';
    $imageData = [];
    foreach (glob($dir) as $file_path) {
        $file_info = new SplFileInfo($file_path);
        $file_name = $file_info-&gt;getFilename();
        $extension = $file_info-&gt;getExtension();
        $image_binary = file_get_contents($file_path);
        $imageData[] = [
            'key'  =&gt; 'sample_image/' . $file_name,
            'body' =&gt; $image_binary,
            'mimeType' =&gt; $extension
        ];
    }
    $aws3Util-&gt;bulkPutS3ContentsBinary(getenv('BUCKET_NAME'), $imageData);
}</pre>
AWSS3Util.php
<pre class="lang:default decode:true ">&lt;?php

use Aws\S3\S3Client;
use Aws\S3\Exception\S3Exception;
use Aws\CommandPool;

class AWSS3Util
{
    private $credentials = [];

    private $region = '';

    private $version = '';

    private $s3Client = null;

    /**
     *
     * 一括S3への保存(バイナリデータを直で)
     *
     * @param string $bucket    バケット名
     * @param mixed  $imageData key =&gt; binaryデータ
     * @param string $mimeType  mime_type
     */
    public function bulkPutS3ContentsBinary($bucket, $imageData)
    {
        $commands = [];
        foreach ($imageData as $eachImageData) {

            $commands[] = $this-&gt;s3Client-&gt;getCommand('PutObject', [
                    'Bucket' =&gt; $bucket,
                    'Key'    =&gt; $eachImageData['key'],
                    'Body' =&gt; $eachImageData['body'],
                    'ContentType'=&gt; 'image/' . $eachImageData['mimeType'],
                    'ACL' =&gt; 'public-read'
            ]);
        }

        $pool = new CommandPool($this-&gt;s3Client, $commands);
        $promise = $pool-&gt;promise();
        // Force the pool to complete synchronously
        $promise-&gt;wait();
    }

    /**
     * S3からファイルを保存
     *
     * @param string $bucket  S3のバケット(トップのディレクトリのようなもの)
     * @param string $fileDir ファイルディレクトリ
     * @param string $imageData アップロードデータ
     */
    public function bulkSaveS3Contents($bucket, $fileDir, $imageData)
    {
        $commands = [];
        foreach ($imageData as $eachImageData) {

            $fileArr = explode("/", $eachImageData);
            $lastIndex = count($fileArr);
            $fileName = $fileArr[$lastIndex - 1];

            if (!file_exists($fileDir)) {
                mkdir($fileDir, 0777, true);
            }

            $filePath = sprintf("%s/%s", $fileDir, $fileName);

            $commands[] = $this-&gt;s3Client-&gt;getCommand('GetObject', [
                'Bucket' =&gt; $bucket,
                'Key'    =&gt; $eachImageData,
                'SaveAs' =&gt; $filePath
            ]);
        }

        $pool = new CommandPool($this-&gt;s3Client, $commands);
        $promise = $pool-&gt;promise();
        // Force the pool to complete synchronously
        $promise-&gt;wait();

    }

}</pre>
