<h3>使用できるサービスについて</h3>
<h4>functions</h4>
ここにAPIを実装することができます。

<span class="lang:default decode:true crayon-inline ">functions/index.js </span>
<pre class="lang:default decode:true ">const functions = require('firebase-functions');
const firebase = require('firebase');
const config = require('./config.js');
const Sugar = require('sugar');
const express = require('express');
const cors = require('cors');
const app = express();
const bodyParser = require('body-parser');

firebase.initializeApp(config.firebaseConfig);
const database = firebase.database();

app.use(cors())
app.use(bodyParser.urlencoded({
    extended: true
}));
app.use(bodyParser.json());

//新規追加
app.post('/:jname', (req, res) =&gt; {

  let jname = req.params.jname;
  let Ref = database.ref(jname);
  let data = req.body;
  Ref.push(data);

  res.header('Content-Type', 'application/json; charset=utf-8');
  res.status(201).json({result: 'ok',res:data});
});

//一覧取得
app.get('/:jname', (req, res) =&gt; {

  let jname = req.params.jname;
  database.ref(jname).once('value', (snapshot) =&gt; {
    let items = snapshot.val();
    let data = [];

    for(var key in items) {
        let each_item = items[key];
        each_item['key'] = key;
        data.push(each_item);
    }

    res.header('Content-Type', 'application/json; charset=utf-8');

    let res_data = {};
    res_data[jname] = data;
    res.send(res_data);
  });
});

//個別編集
app.put('/:jname/:hash_key', (req, res) =&gt; {

  let jname = req.params.jname;
  let hash_key = req.params.hash_key;

  let data = req.body;
  database.ref(jname).child(hash_key).update(data)

  res.header('Content-Type', 'application/json; charset=utf-8');
  res.status(201).json({result: 'ok',res:data});
});

//個別削除
app.delete('/:jname/:hash_key', (req, res) =&gt; {
  let jname = req.params.jname;
  let hash_key = req.params.hash_key;
  database.ref(jname).child(hash_key).remove();
  res.header('Content-Type', 'application/json; charset=utf-8');
  res.status(201).json({result: 'delete ', hash_key: hash_key});
});

//全削除
app.delete('/:jname', (req, res) =&gt; {
  let jname = req.params.jname;
  database.ref(jname).remove();
  res.header('Content-Type', 'application/json; charset=utf-8');
  res.status(201).json({result: 'ok all delete'});
});


/*ローカルテスト時
app.listen(3000, () =&gt; {
  console.log('Example app listening on port 3000!');
});
*/

//exports.v1 = functions.https.onRequest(app);
</pre>
一般的な新規作成、一覧、編集、削除(おまけで全削除)のRESTAPIです。とりあえず認証などはかけずに作ってみました。

上記のようなAPIを書いておき、firebaseにデプロイするとRESTAPIができています。

それぞれ対応するHTTPリクエストを書いて起きた時に、しっかりと結果を返してくれます。

ローカルでテストをするときは<span class="lang:default decode:true crayon-inline ">node functions/index.js</span> とうちnodeのサーバーを立てましょう。

functionsの部分は独立した部分のようでいわゆるバックエンド側になるかと思います。

このディレクトリ自体にpackage.jsonを置いてライブラリをインストールし、このディレクトリ独自で管理することが一般的のようです。
<h4>hosting</h4>
冒頭でも書きましたが、当初KVSのサーバーだけをかりてファイルなどは別の箇所に置いておくものかと思いました。(そういう使い方ももちろんできますが・・)

.firebaserc
<pre class="lang:default decode:true">{
  "database": {
    "rules": "database.rules.json"
  },
  "hosting": {
    "public": "public",
    "ignore": [
      "firebase.json",
      "**/.*",
      "**/node_modules/**"
    ],
    "rewrites": [
      {
        "source": "**",
        "destination": "/index.html"
      }
    ]
  },
  "storage": {
    "rules": "storage.rules"
  }
}
</pre>
上記のファイルのhostingの部分がfirebaseのホスティングサービス(hosting)の設定になります。(<span class="lang:default decode:true crayon-inline ">firebase init</span> 時に作られます。)

一般的にはpublic以下に公開ファイルをおくことが多いかと思います。ここにindex.htmlなどを置いてアクセスしてあげればfirebaseにデプロイした時にアプリを確認することができます。

